  group('validateAICoachInput', () {
    // テスト用のヘルパー関数
    Player createPlayer({
      Handedness pitchingHand = Handedness.right,
      DateTime? birthday,
    }) {
      return Player(
        id: 'test-player-id',
        name: 'Test Player',
        pitchingHand: pitchingHand,
        birthday: birthday,
      );
    }

    List<Ball> createPitchingBalls(int count, {bool withPitchTypes = true}) {
      return List.generate(
        count,
        (index) => Ball(
          id: index,
          pitchType: withPitchTypes
              ? const PitchType(
                  id: 'fastball-id',
                  pitchType: 'fastball',
                )
              : null,
        ),
      );
    }

    group('投球データ数のバリデーション', () {
      test('10個未満の投球データの場合、notEnoughPitchingData を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(9);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.notEnoughPitchingData);
      });

      test('ちょうど10個の投球データの場合、次のバリデーションに進む', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, isNot(AICoachValidator.notEnoughPitchingData));
      });

      test('空の投球データの場合、notEnoughPitchingData を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = <Ball>[];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.notEnoughPitchingData);
      });
    });

    group('球種タグのバリデーション', () {
      test('すべての投球に球種タグがある場合、次のバリデーションに進む', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = createPitchingBalls(10, withPitchTypes: true);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, isNot(AICoachValidator.missingPitchTypes));
      });

      test('球種タグが null の投球がある場合、missingPitchTypes を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = [
          ...createPitchingBalls(9, withPitchTypes: true),
          const Ball(id: 999, pitchType: null),
        ];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPitchTypes);
      });

      test('球種タイプが "none" の投球がある場合、missingPitchTypes を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = [
          ...createPitchingBalls(9, withPitchTypes: true),
          const Ball(
            id: 999,
            pitchType: PitchType(
              id: 'none-id',
              pitchType: 'none',
            ),
          ),
        ];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPitchTypes);
      });

      test('複数の投球に球種タグがない場合、missingPitchTypes を返す', () {
        final player = createPlayer(birthday: DateTime(2000, 1, 1));
        final pitchingBalls = [
          ...createPitchingBalls(8, withPitchTypes: true),
          const Ball(id: 998, pitchType: null),
          const Ball(id: 999, pitchType: null),
        ];

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPitchTypes);
      });
    });

    group('プレイヤー情報のバリデーション', () {
      test('プレイヤーが null の場合、missingPlayerInfo を返す', () {
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: null,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('投球利き腕が none の場合、missingPlayerInfo を返す', () {
        final player = createPlayer(
          pitchingHand: Handedness.none,
          birthday: DateTime(2000, 1, 1),
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('誕生日が null の場合、missingPlayerInfo を返す', () {
        final player = createPlayer(
          pitchingHand: Handedness.right,
          birthday: null,
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
        );

        expect(result, AICoachValidator.missingPlayerInfo);
      });

      test('投球利き腕と誕生日の両方が欠けている場合、missingPlayerInfo を返す', () {
        final player = createPlayer(
          pitchingHand: Handedness.none,
          birthday: null,
        );
        final pitchingBalls = createPitchingBalls(10);

        final result = validateAICoachInput(
          player: player,
          pitchingBalls: pitchingBalls,
          currentUsage: 0,
          maxUsage: 10,
