// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_dialog.dart';
import 'package:baseball_detector_flutter/views/hooks/use_operation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_ai_coach_count.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/hooks/use_ai_coach_validation.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_session_refresh.dart';

Future<void> Function({
  required List<Ball> hittingBalls,
  required List<Ball> pitchingBalls,
  bool shouldShowCautionDialog,
}) useAIReportGeneration({
  required Player? player,
  required ValueNotifier<Session> currentSession,
}) {
  final context = useContext();
  final ref = useWidgetRef();
  final repository = ref.watch(repositoryProvider);
  final handleOperation = useOperation<String>();
  final usage = useAICoachCount();
  final validateAICoach = useAICoachValidation();

  final onRefresh = useSessionRefresh(currentSession: currentSession);

  return ({
    required List<Ball> hittingBalls,
    required List<Ball> pitchingBalls,
    bool shouldShowCautionDialog = true,
  }) async {
    final sessionId = currentSession.value.id;
    final teamId = currentSession.value.teamId;

    if (sessionId == null || teamId == null) return;

    // バリデーション実行
    final validationResult = validateAICoach(
      player: player,
      pitchingBalls: pitchingBalls,
    );

    switch (validationResult) {
      case AICoachValidator.notEnoughPitchingData:
        context.showErrorSnackBar(
          context.l10n.ai_coach_report__request_need_pitching_data,
        );
        return;
      case AICoachValidator.missingPitchTypes:
        context.showErrorSnackBar(
          context.l10n.ai_coach_report__request_need_pitch_type,
        );
        return;
      case AICoachValidator.missingPlayerInfo:
        context.showErrorSnackBar(
          context.l10n.ai_coach_report__request_need_player_info,
        );
        return;
      case AICoachValidator.usageLimitReached:
        context.showErrorSnackBar(
          context.l10n.ai_coach_report__request_limit_reached_message,
        );
        return;
      case AICoachValidator.ok:
        break;
    }

    if (shouldShowCautionDialog) {
      final shouldGenerate = await showDialog<bool>(
        context: context,
        barrierDismissible: true,
        builder: (dialogContext) {
          final maxUsageText = usage.maxUsage?.toString() ?? '--';
          final currentUsageText = usage.currentUsage?.toString() ?? '--';

          return CustomDialog.normal(
            title: dialogContext.l10n.ai_coach_report__request_confirm_title,
            builder: (innerContext, _) {
              return Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    dialogContext
                        .l10n.ai_coach_report__usage_count_will_increase,
                  ),
                  const Gap(16),
                  Text(
                    dialogContext.l10n
                        .ai_coach_report__request_confirm_usage_message(
                      maxUsageText,
                      currentUsageText,
                    ),
                  ),
                ],
              );
            },
            aboveButtonText: dialogContext
                .l10n.ai_coach_report__request_confirm_positive_button_label,
            aboveButtonAction: (actionContext) {
              Navigator.of(actionContext).pop(true);
            },
            belowButtonText: dialogContext
                .l10n.ai_coach_report__request_confirm_negative_button_label,
            belowButtonAction: (actionContext) {
              Navigator.of(actionContext).pop(false);
            },
          );
        },
      );

      if (shouldGenerate != true) return;
    }

    await handleOperation(
      operation:
          repository.createAIReport(teamId: teamId, sessionId: sessionId),
      onSucceeded: (_) async {
        await onRefresh();
        return context.mounted
            ? context.l10n.ai_coach_report__request_success_message
            : null;
      },
      onFailed: (failure) async =>
          context.mounted ? failure.translate(context.l10n) : null,
      shouldSendErrorLog: (failure) =>
          !_ignoreFailure.contains(failure.runtimeType),
    );
  };
}

// エラーログを送らない Failure
const _ignoreFailure = [
  PitchTypeNotTaggedForAllResourcesFailure,
  PlayerBirthdayMissingFailure,
  PlayerThrowHandMissingFailure,
  SessionHasNoResourcesFailure,
];

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball.dart' show Ball;
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/all_balls_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/hooks/use_ai_coach_validation.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/hooks/use_ai_report_generation.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class EmptyContainer extends HookConsumerWidget {
  const EmptyContainer({
    required this.currentSession,
    required this.player,
    super.key,
  });

  final ValueNotifier<Session> currentSession;
  final Player? player;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    final validateAICoach = useAICoachValidation();

    final generateReport = useAIReportGeneration(
      player: player,
      currentSession: currentSession,
    );

    return LayoutBuilder(builder: (context, constraints) {
      final sessionId = currentSession.value.id;
      final teamId = currentSession.value.teamId;

      if (sessionId == null || teamId == null) {
        return const SizedBox.shrink();
      }

      return SingleChildScrollView(
        physics: const AlwaysScrollableScrollPhysics(),
        child: ConstrainedBox(
          constraints: BoxConstraints(minHeight: constraints.maxHeight),
          child: Center(
            child: AllBallsContainer(
              teamId: teamId,
              sessionId: sessionId,
              builder: ({
                required List<Ball> hittingBalls,
                required List<Ball> pitchingBalls,
              }) {
                // バリデーション実行
                final validationResult = validateAICoach(
                  player: player,
                  pitchingBalls: pitchingBalls,
                );
                return Container(
                  width: double.infinity,
                  alignment: Alignment.center,
                  child: Padding(
                    padding: const EdgeInsets.all(20),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Text(
                          context
                              .l10n.ai_coach_report__request_empty_state_title,
                          style: theme.textTheme.titleLarge?.copyWith(
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                        const Gap(24),
                        Text(
                          context.l10n
                              .ai_coach_report__request_empty_state_subtitle,
                          style: theme.textTheme.bodyMedium?.copyWith(
                            color: colorScheme.onSurfaceVariant,
                          ),
                        ),
                        const Gap(20),
                        requirementRow(
                          context,
                          satisfied: validationResult !=
                              AICoachValidator.notEnoughPitchingData,
                          label: context.l10n
                              .ai_coach_report__request_requirement_pitching_data,
                        ),
                        const Gap(12),
                        requirementRow(
                          context,
                          satisfied: validationResult !=
                              AICoachValidator.missingPitchTypes,
                          label: context.l10n
                              .ai_coach_report__request_requirement_pitch_type,
                        ),
                        const Gap(20),
                        SizedBox(
                          width: double.infinity,
                          child: ElevatedButton.icon(
                            onPressed: () async {
                              await generateReport(
                                hittingBalls: hittingBalls,
                                pitchingBalls: pitchingBalls,
                              );
                            },
                            style: ButtonStyle(
                              shape: WidgetStateProperty.all(
                                RoundedRectangleBorder(
                                  borderRadius: BorderRadius.circular(4),
                                ),
                              ),
                            ),
                            icon: Icon(Icons.auto_fix_high),
                            label: Padding(
                              padding:
                                  const EdgeInsets.symmetric(vertical: 16.0),
                              child: Text(context
                                  .l10n.ai_coach_report__request_button_label),
                            ),
                          ),
                        ),
                      ],
                    ),
                  ),
                );
              },
            ),
          ),
        ),
      );
    });
  }

  Widget requirementRow(
    BuildContext context, {
    required bool satisfied,
    required String label,
  }) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    final borderColor =
        satisfied ? ColorManager.main : colorScheme.outlineVariant;
    final textColor =
        satisfied ? colorScheme.onSurface : colorScheme.onSurfaceVariant;
    final textWeight = satisfied ? FontWeight.w600 : FontWeight.w400;

    return Row(
      children: [
        Checkbox(
          value: satisfied,
          onChanged: null,
          materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
          visualDensity: VisualDensity.compact,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(100),
          ),
          side: BorderSide(color: borderColor, width: 1.5),
          fillColor: WidgetStateProperty.resolveWith<Color?>(
            (states) => satisfied ? ColorManager.main : Colors.transparent,
          ),
          checkColor: colorScheme.surface,
        ),
        const Gap(12),
        Expanded(
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Text(
                label,
                style: theme.textTheme.bodyMedium?.copyWith(
                  color: textColor,
                  fontWeight: textWeight,
                ),
              ),
            ],
          ),
        ),
      ],
    );
  }
}
